<?php
declare(strict_types=1);
require_once __DIR__.'/../app/support_chat.php';
proteger_admin();support_chat_ensure_schema(getPDO());
if(empty($_SESSION['support_chat_csrf']))$_SESSION['support_chat_csrf']=bin2hex(random_bytes(24));
$csrf=(string)$_SESSION['support_chat_csrf'];
?><!doctype html><html lang="pt-BR"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"><title>Simulação · Suporte FERA</title><style>
*{box-sizing:border-box}html,body{margin:0;height:100%;font-family:Inter,system-ui,sans-serif;background:#090f14;color:#e9edef}button,input{font:inherit}button{border:0;background:none;cursor:pointer}.sim-page{height:100dvh;display:grid;place-items:center;padding:16px}.phone{width:min(430px,100%);height:min(820px,calc(100dvh - 32px));display:flex;flex-direction:column;overflow:hidden;border:1px solid #34434b;border-radius:18px;background:#0b141a;box-shadow:0 25px 90px #000b}.head{display:flex;align-items:center;gap:11px;padding:12px 14px;background:#075e54}.avatar{width:42px;height:42px;border-radius:50%;display:grid;place-items:center;background:#00a884;font-weight:900}.head div:nth-child(2){flex:1}.head b{display:block}.head small{font-size:11px}.head a{color:#fff;text-decoration:none;font-size:20px}.picker{padding:12px;background:#111b21;border-bottom:1px solid #253139}.picker input{width:100%;padding:10px 12px;border:1px solid #34434b;border-radius:20px;background:#202c33;color:#fff;outline:0}.results{max-height:190px;overflow:auto}.student{padding:10px;border-bottom:1px solid #26343c;cursor:pointer;font-size:12px}.student:hover{background:#202c33}.messages{flex:1;min-height:0;overflow-y:auto;display:flex;flex-direction:column;gap:6px;padding:12px;background-color:#0b141a;background-image:radial-gradient(#253139 1px,transparent 1px);background-size:18px 18px}.empty{margin:auto;text-align:center;color:#8696a0;font-size:12px}.msg{max-width:84%;align-self:flex-start;padding:7px 9px 4px;border-radius:8px;background:#202c33;font-size:12px;line-height:1.4;box-shadow:0 1px 2px #0005}.msg.own{align-self:flex-end;background:#005c4b}.msg .sign{font-size:8px;color:#67e8f9;font-weight:800}.msg .time{display:block;text-align:right;color:#9ca3af;font-size:7px;margin-left:15px}.msg img,.msg video{display:block;width:auto;max-width:min(100%,250px);max-height:300px;object-fit:contain;border-radius:6px}.msg audio{display:block;width:220px;max-width:100%;height:32px}.file{color:#93c5fd;text-decoration:none}.compose{position:relative;display:flex;align-items:center;gap:3px;padding:8px;background:#202c33}.compose input[type=text]{min-width:0;flex:1;height:38px;padding:9px 12px;border:0;border-radius:20px;background:#2a3942;color:#fff;outline:0}.icon{width:36px;height:36px;border-radius:50%;display:grid;place-items:center;color:#aebac1;font-size:18px}.plus{font-size:25px}.send{background:#00a884;color:#fff}.menu,.emojis{display:none;position:absolute;z-index:10;left:8px;bottom:56px;border:1px solid #3b4a54;border-radius:13px;background:#202c33;box-shadow:0 14px 40px #000b}.menu.open,.emojis.open{display:block}.menu{width:215px;padding:7px}.menu button{display:flex;width:100%;gap:10px;padding:10px;color:#e9edef;border-radius:8px;text-align:left}.menu button:hover{background:#2a3942}.emojis{width:min(350px,calc(100vw - 28px));padding:11px}.emoji-grid{display:grid;grid-template-columns:repeat(8,1fr);gap:3px}.emoji-grid button{height:32px;font-size:20px;border-radius:6px}.emoji-grid button:hover{background:#34434b}.record{display:none;align-items:center;gap:10px;min-height:54px;padding:8px 12px;background:#202c33}.record.open{display:flex}.record button{width:38px;height:38px;border-radius:50%;color:#fff}.trash{color:#ef4444!important}.dot{width:8px;height:8px;border-radius:50%;background:#fb7185;animation:pulse 1s infinite}.wave{flex:1;overflow:hidden;color:#9ca3af;letter-spacing:2px;white-space:nowrap}@keyframes pulse{50%{opacity:.4}}.test{position:fixed;top:8px;left:8px;padding:5px 9px;border-radius:10px;background:#facc15;color:#111;font-size:9px;font-weight:900}@media(max-width:520px){.sim-page{padding:0}.phone{width:100%;height:100dvh;border:0;border-radius:0}.test{display:none}.msg img,.msg video{max-width:min(100%,220px);max-height:260px}}
</style></head><body><span class="test">MODO TESTE</span><main class="sim-page"><section class="phone"><header class="head"><div class="avatar">⚡</div><div><b>Suporte FERA</b><small>Normalmente responde rápido</small></div><a href="javascript:window.close()" title="Fechar">✕</a></header><div class="picker" id="picker"><input id="search" placeholder="Escolha o aluno para simular"><div class="results" id="results"></div></div><div class="messages" id="messages"><div class="empty">Busque e selecione um aluno para começar.</div></div><form class="compose" id="compose"><input type="file" id="file" hidden><div class="menu" id="menu"><button type="button" data-accept="image/*,video/*">▣ Fotos e vídeos</button><button type="button" data-accept="audio/*">🎧 Áudio</button><button type="button" data-accept=".pdf,.doc,.docx,.xls,.xlsx,.txt,.zip">▤ Documento</button></div><div class="emojis" id="emojis"><div class="emoji-grid" id="emojiGrid"></div></div><button type="button" class="icon plus" id="plus">＋</button><button type="button" class="icon" id="emoji">☺</button><input type="text" id="text" placeholder="Mensagem" disabled><button type="button" class="icon" id="mic">🎙</button><button class="icon send">➤</button></form><div class="record" id="record"><button type="button" class="trash" id="discard">🗑</button><span class="dot"></span><strong id="time">0:00</strong><div class="wave">••••••••••••••</div><button type="button" id="pause">Ⅱ</button><button type="button" class="send" id="audioSend">➤</button></div></section></main><script>
const csrf=<?=json_encode($csrf)?>;let conversation=0,last=0,recording=null,searchTimer;const esc=s=>String(s??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));async function api(url,opt={}){const r=await fetch(url,opt),j=await r.json();if(!j.ok)throw new Error(j.error||'Falha');return j}function post(action,data={},attachment=null){const f=new FormData();f.append('csrf',csrf);f.append('action',action);Object.entries(data).forEach(([k,v])=>f.append(k,v));if(attachment)f.append('attachment',attachment);return api('suporte_chat.php',{method:'POST',body:f})}function fmt(v){return v?new Date(v.replace(' ','T')).toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}):''}function html(m){const own=m.sender_type==='student',url='../public/'+esc(m.attachment_url||'');let c=esc(m.body||'').replace(/\n/g,'<br>');if(m.message_type==='image')c=`<img src="${url}">`+c;if(m.message_type==='video')c=`<video controls src="${url}"></video>`+c;if(m.message_type==='audio')c=`<audio controls src="${url}"></audio>`+c;if(m.message_type==='file')c=`<a class="file" target="_blank" href="${url}">📄 ${esc(m.attachment_name)}</a>`+c;return`<div class="msg ${own?'own':''}">${!own?`<div class="sign">${esc(m.sender_name||'Suporte')}</div>`:''}${c}<span class="time">${fmt(m.created_at)} ${own?'✓✓':''}</span></div>`}async function refresh(full=false){if(!conversation)return;const j=await api(`suporte_chat.php?api=messages&conversation_id=${conversation}&after=${full?0:last}`);if(full)messages.innerHTML='';j.messages.forEach(m=>{messages.insertAdjacentHTML('beforeend',html(m));last=Math.max(last,+m.id)});if(j.messages.length)messages.scrollTop=messages.scrollHeight}search.oninput=()=>{clearTimeout(searchTimer);searchTimer=setTimeout(async()=>{if(search.value.trim().length<2)return results.innerHTML='';const j=await api('suporte_chat.php?api=students&q='+encodeURIComponent(search.value));results.innerHTML=j.items.map(x=>`<div class="student" data-id="${x.id}"><b>${esc(x.nome)}</b><br>${esc(x.email)}</div>`).join('');results.querySelectorAll('.student').forEach(x=>x.onclick=async()=>{const j=await post('create_test',{user_id:x.dataset.id});conversation=j.conversation_id;last=0;picker.style.display='none';text.disabled=false;refresh(true)})},250)};compose.onsubmit=async e=>{e.preventDefault();const attachment=file.files[0];if(!conversation||(!text.value.trim()&&!attachment))return;try{await post('send',{conversation_id:conversation,sender_type:'student',body:text.value},attachment);text.value='';file.value='';refresh()}catch(err){alert(err.message)}};plus.onclick=()=>{if(!conversation)return alert('Escolha um aluno.');emojis.classList.remove('open');menu.classList.toggle('open')};menu.querySelectorAll('[data-accept]').forEach(b=>b.onclick=()=>{file.accept=b.dataset.accept;menu.classList.remove('open');file.click()});file.onchange=()=>file.files[0]&&compose.requestSubmit();const emojiList=['😀','😁','😂','🤣','😊','😍','🥰','😘','😎','🤩','🥳','😇','🙂','😉','🤔','🙌','👏','👍','👎','🙏','💪','❤️','💛','💚','🔥','✨','🎉','✅','❌','⚠️','📌','💡','📚','🎓','💬','📲','👋','🤝','👌','🚀'];emojiGrid.innerHTML=emojiList.map(x=>`<button type="button">${x}</button>`).join('');emojiGrid.querySelectorAll('button').forEach(b=>b.onclick=()=>{text.value+=b.textContent;text.focus()});emoji.onclick=()=>{menu.classList.remove('open');emojis.classList.toggle('open')};function mime(){for(const t of ['audio/webm;codecs=opus','audio/ogg;codecs=opus','audio/webm'])if(MediaRecorder.isTypeSupported(t))return t;return''}function closeRecord(){clearInterval(recording?.timer);record.classList.remove('open');compose.style.display='';pause.textContent='Ⅱ';recording=null}mic.onclick=async()=>{if(!conversation)return alert('Escolha um aluno.');try{const stream=await navigator.mediaDevices.getUserMedia({audio:true}),type=mime(),rec=new MediaRecorder(stream,type?{mimeType:type}:{}),chunks=[];recording={rec,stream,type,chunks,send:false,seconds:0,timer:null};rec.ondataavailable=e=>e.data.size&&chunks.push(e.data);rec.onstop=async()=>{stream.getTracks().forEach(t=>t.stop());const state=recording,send=state?.send,actual=rec.mimeType||type||'audio/webm';closeRecord();if(!send||!chunks.length)return;const f=new File([new Blob(chunks,{type:actual})],`audio-${Date.now()}.${actual.includes('ogg')?'ogg':'webm'}`,{type:actual});await post('send',{conversation_id:conversation,sender_type:'student',body:''},f);refresh()};rec.start(250);compose.style.display='none';record.classList.add('open');time.textContent='0:00';recording.timer=setInterval(()=>{if(rec.state==='recording'){recording.seconds++;time.textContent=Math.floor(recording.seconds/60)+':'+String(recording.seconds%60).padStart(2,'0')}},1000)}catch(err){alert(err.name==='NotAllowedError'?'Permita o microfone no navegador.':err.message)}};discard.onclick=()=>{if(recording){recording.send=false;recording.rec.stop()}};pause.onclick=()=>{if(!recording)return;if(recording.rec.state==='recording'){recording.rec.pause();pause.textContent='▶'}else{recording.rec.resume();pause.textContent='Ⅱ'}};audioSend.onclick=()=>{if(recording){recording.send=true;recording.rec.stop()}};text.oninput=()=>conversation&&post('typing',{conversation_id:conversation,actor_type:'student',actor_name:'Aluno'}).catch(()=>{});setInterval(()=>refresh(),3000);
</script></body></html>
